sql:
SELECT average_stay
FROM admission_types
WHERE admission_type_name = 'Emergency Room';

SELECT hospital_id, reason_for_admission, admission_source
FROM admission_rates
WHERE total_patients > 500;

SELECT hospital_id, COUNT(*) AS admission_rate_count, AVG(admit_all_ages) AS average_admission_rate
FROM admission_rates
GROUP BY hospital_id;

SELECT date, SUM(total_visits) AS total_visits
FROM visit_statistics
GROUP BY date;

SELECT visit_all_ages, total_visits
FROM visit_statistics
WHERE hospital_id = 1 AND visit_type_id = 2;

